/**
 * SMS notification adapter.
 *
 * Implements NotificationAdapter for the 'sms' channel.
 * Formats the notification payload as a short text message and delivers
 * via a configurable transport (real provider or in-memory for testing).
 *
 * NOTE: User preferences (src/models/user-preferences.ts) currently only
 * support email channel preferences. SMS preferences (enabled/frequency/
 * subscribed categories) need to be added before SMS can be gated by
 * user preferences. See COORDINATION.md for details.
 */

import type { NotificationPayload } from '../models/notification.js';
import type {
  NotificationAdapter,
  NotificationDeliveryResult,
} from './notification.adapter.js';
import { Logger } from '../utils/logger.js';

/** A sent SMS record with delivery metadata. */
export interface SentSms {
  to: string;
  message: string;
  sentAt: Date;
  notificationType: string;
}

/** Configuration for the SMS adapter. */
export interface SmsAdapterConfig {
  /** Resolve a recipient identifier to a phone number. */
  resolveRecipient?: (recipient: string) => string | null;
  /** Transport function — called for actual delivery. Return true for success. */
  transport?: (to: string, message: string) => Promise<boolean>;
}

const PHONE_REGEX = /^\+?[1-9]\d{6,14}$/;

function isValidPhoneNumber(value: string): boolean {
  return PHONE_REGEX.test(value);
}

export class SmsAdapter implements NotificationAdapter {
  readonly channel = 'sms';
  private logger = new Logger('SmsAdapter');
  private sentMessages: SentSms[] = [];
  private config: SmsAdapterConfig;

  constructor(config?: Partial<SmsAdapterConfig>) {
    this.config = {
      resolveRecipient: config?.resolveRecipient,
      transport: config?.transport,
    };
  }

  /**
   * Resolve a recipient identifier to a deliverable phone number.
   * Uses the configured resolver if present, otherwise returns the raw
   * recipient if it looks like a phone number.
   */
  resolveRecipient(recipient: string): string | null {
    if (this.config.resolveRecipient) {
      return this.config.resolveRecipient(recipient);
    }
    return isValidPhoneNumber(recipient) ? recipient : null;
  }

  /**
   * Format a notification payload into a short SMS message.
   * SMS messages are plain text with subject and body.
   */
  formatMessage(payload: NotificationPayload): string {
    return `${payload.subject}\n${payload.body}`;
  }

  /**
   * Send an SMS notification.
   * Resolves the recipient, formats the message, and delivers via the
   * configured transport (or stores in-memory if no transport is set).
   */
  async send(payload: NotificationPayload): Promise<NotificationDeliveryResult> {
    try {
      const resolvedNumber = this.resolveRecipient(payload.recipient);
      if (!resolvedNumber) {
        const msg = `Cannot resolve recipient to phone number: ${payload.recipient}`;
        this.logger.error(msg);
        return { success: false, error: msg };
      }

      const message = this.formatMessage(payload);
      this.logger.info(`Sending SMS to ${resolvedNumber}: ${payload.subject}`);

      if (this.config.transport) {
        const ok = await this.config.transport(resolvedNumber, message);
        if (!ok) {
          const msg = `SMS delivery failed for ${resolvedNumber}`;
          this.logger.error(msg);
          return { success: false, error: msg };
        }
      }

      this.sentMessages.push({
        to: resolvedNumber,
        message,
        sentAt: new Date(),
        notificationType: payload.notificationType,
      });

      return { success: true };
    } catch (err) {
      const message = err instanceof Error ? err.message : 'Unknown SMS error';
      this.logger.error(`Failed to send SMS to ${payload.recipient}: ${message}`);
      return { success: false, error: message };
    }
  }

  /**
   * Get all SMS messages sent through this adapter. Useful for testing.
   */
  getSentMessages(): SentSms[] {
    return [...this.sentMessages];
  }

  /**
   * Clear sent message history.
   */
  clearSentMessages(): void {
    this.sentMessages = [];
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import { SmsAdapter } from '../../src/adapters/sms.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

function makePayload(overrides?: Partial<NotificationPayload>): NotificationPayload {
  return {
    recipient: '+15551234567',
    subject: 'Order Confirmation: order-1',
    body: 'Your order has been placed. Items: Widget x2. Total: $20.00',
    channel: 'sms',
    notificationType: 'order_confirmation',
    ...overrides,
  };
}

describe('SmsAdapter', () => {
  let adapter: SmsAdapter;

  beforeEach(() => {
    adapter = new SmsAdapter();
  });

  describe('channel property', () => {
    it('should be sms', () => {
      expect(adapter.channel).toBe('sms');
    });
  });

  describe('resolveRecipient', () => {
    it('should accept a valid phone number', () => {
      expect(adapter.resolveRecipient('+15551234567')).toBe('+15551234567');
    });

    it('should accept a phone number without plus prefix', () => {
      expect(adapter.resolveRecipient('15551234567')).toBe('15551234567');
    });

    it('should reject an invalid phone number', () => {
      expect(adapter.resolveRecipient('not-a-phone')).toBeNull();
    });

    it('should reject an email address', () => {
      expect(adapter.resolveRecipient('user@example.com')).toBeNull();
    });

    it('should use custom resolver when configured', () => {
      const customAdapter = new SmsAdapter({
        resolveRecipient: (r) => (r === 'user-1' ? '+15559999999' : null),
      });
      expect(customAdapter.resolveRecipient('user-1')).toBe('+15559999999');
      expect(customAdapter.resolveRecipient('user-2')).toBeNull();
    });
  });

  describe('formatMessage', () => {
    it('should combine subject and body', () => {
      const msg = adapter.formatMessage(makePayload());
      expect(msg).toBe('Order Confirmation: order-1\nYour order has been placed. Items: Widget x2. Total: $20.00');
    });
  });

  describe('send', () => {
    it('should send and record SMS for valid phone number', async () => {
      const result = await adapter.send(makePayload());

      expect(result.success).toBe(true);
      const sent = adapter.getSentMessages();
      expect(sent).toHaveLength(1);
      expect(sent[0]?.to).toBe('+15551234567');
      expect(sent[0]?.message).toContain('Order Confirmation');
      expect(sent[0]?.notificationType).toBe('order_confirmation');
    });

    it('should fail when recipient cannot be resolved', async () => {
      const result = await adapter.send(makePayload({ recipient: 'user@example.com' }));

      expect(result.success).toBe(false);
      expect(result.error).toContain('Cannot resolve recipient to phone number');
      expect(adapter.getSentMessages()).toHaveLength(0);
    });

    it('should use custom transport when configured', async () => {
      const transported: { to: string; message: string }[] = [];
      const customAdapter = new SmsAdapter({
        transport: async (to, message) => {
          transported.push({ to, message });
          return true;
        },
      });

      const result = await customAdapter.send(makePayload());

      expect(result.success).toBe(true);
      expect(transported).toHaveLength(1);
      expect(transported[0]?.to).toBe('+15551234567');
      expect(customAdapter.getSentMessages()).toHaveLength(1);
    });

    it('should fail when transport returns false', async () => {
      const customAdapter = new SmsAdapter({
        transport: async () => false,
      });

      const result = await customAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.error).toContain('SMS delivery failed');
      expect(customAdapter.getSentMessages()).toHaveLength(0);
    });

    it('should catch transport errors and return failure', async () => {
      const customAdapter = new SmsAdapter({
        transport: async () => {
          throw new Error('Network timeout');
        },
      });

      const result = await customAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.error).toBe('Network timeout');
      expect(customAdapter.getSentMessages()).toHaveLength(0);
    });

    it('should send multiple messages and track all', async () => {
      await adapter.send(makePayload());
      await adapter.send(makePayload({ notificationType: 'order_status_update' }));

      const sent = adapter.getSentMessages();
      expect(sent).toHaveLength(2);
      expect(sent[0]?.notificationType).toBe('order_confirmation');
      expect(sent[1]?.notificationType).toBe('order_status_update');
    });
  });

  describe('clearSentMessages', () => {
    it('should clear all recorded messages', async () => {
      await adapter.send(makePayload());
      expect(adapter.getSentMessages()).toHaveLength(1);

      adapter.clearSentMessages();
      expect(adapter.getSentMessages()).toHaveLength(0);
    });
  });

  describe('integration with NotificationService', () => {
    it('should work when registered with notification service', async () => {
      const { EventBus } = await import('../../src/events/event-bus.js');
      const { NotificationService, resetNotificationIdCounter } = await import(
        '../../src/services/notification.service.js'
      );

      resetNotificationIdCounter();
      const eventBus = new EventBus();
      const service = new NotificationService(eventBus);
      const smsAdapter = new SmsAdapter();
      service.registerAdapter(smsAdapter);

      expect(smsAdapter.channel).toBe('sms');

      // Send directly through the adapter to verify it works end-to-end
      const result = await smsAdapter.send({
        recipient: '+15551234567',
        subject: 'Order Confirmation: order-1',
        body: 'Your order has been placed.',
        channel: 'sms',
        notificationType: 'order_confirmation',
      });

      expect(result.success).toBe(true);
      expect(smsAdapter.getSentMessages()).toHaveLength(1);
      expect(smsAdapter.getSentMessages()[0]?.notificationType).toBe('order_confirmation');
    });
  });
});

